sql:
SELECT d.*, 
       (SELECT COUNT(*) FROM access_logs WHERE dataset_id = d.dataset_id) AS total_access_count
FROM datasets d;

SELECT band_name
FROM bands
WHERE wavelength > 500;

external_knowledge:
- "group" refers to 'team';
- "interacted with" means 'accessed';
- "different access methods" refers to 'access_type';
- "twist involving the cosine of these counts" means applying the cosine function to the count of datasets accessed;
- "sort them by group and method" means ordering the results by 'team_id' and 'access_type'.

sql:
SELECT survey_id, survey_name
FROM surveys
ORDER BY survey_id;

SELECT team_id, COUNT(dataset_id) AS dataset_count
FROM team_access
GROUP BY team_id;
